  ('locality-6f0ba476-moex-00215', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司X5年底部分權益資料如下：普通股流通在外35,000股，每股面額$10；6%累積且非 參加特別股3,000股，每股面額$40。若特別股已積欠二年股利。X5年12月31日股東會決 議並宣告發放現金股利總額$68,850，試問：普通股每股可得現金股利為何？', '["$1.35", "$1.56", "$1.76", "$1.97"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00216', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司X5年淨利為$956,000。X5年1月1日之權益資料含有普通股流通在外200,000股， 每股面額$10；5%累積特別股60,000股，每股面額$10。甲公司當年度普通股相關交易如下： 4月1日現金增資發行新股50,000股，7月1日買回庫藏股票20,000股，11月1日售出12,000 股的庫藏股票。試問：甲公司X5年普通股每股盈餘為何？', '["$3.83", "$3.95", "$4.03", "$4.17"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00217', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司於X3年初登記設立，核准發行普通股160,000股，每股面額$10，該公司將分兩次發 行，第一次於X3年初以每股$26發行1/2股數，第二次則於X3年底發行剩餘股數。甲公司 X4年初，帳列「資本公積－普通股溢價」為$2,720,000。甲公司第二次發行普通股的每股發 行價為何？', '["$18", "$19", "$27", "$28"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00218', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司之部分財務資料如下：X3年底之機器設備$380,000，累計折舊$120,000；X4年底之機 器設備$520,000，累計折舊$60,000；X3年度機器設備折舊費用$60,000。X3年度該公司出售 一套機器設備其成本$145,000，出售前該設備累計折舊$110,000，售得現金$48,500。試問：甲 公司於X3年之投資活動現金流量為何？', '["$48,500", "($91,500)", "($186,500)", "($236,500)"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00219', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲君為丙公司新進會計人員，正使用間接法來編製現金流量表，X2年相關資料如下：購買一 台機器付款$165,000，權益法認列投資收益$80,000，支付現金股利給股東$50,000，簽發票據 $105,000取得一筆土地，採權益法之長期股權投資收到股利$75,000，發行公司債$280,000。 X2 年度折舊費用$30,000。X2 年度應收帳款淨額減少$32,000，存貨增加$20,000，應付帳款 減少$30,000。X2年度淨利$120,000，期初現金餘額$50,000。丙公司X2年之營業活動現金流 量為何？', '["$127,000", "$147,000", "$207,000", "$287,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00220', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司於X3年3月1日與客戶簽訂銷貨合約，合約中承諾以每件$200銷售商品，總計銷售 件數為100件，每件商品成本為$70，銷貨合約中同時給予客戶退貨權，允許客戶於60天內 無條件退貨，且公司必須全額退費。根據過去的經驗，甲公司評估約有90%的商品不會被退 回。依照國際財務報導準則第15號「客戶合約收入」，甲公司於銷售當日之應收帳款與收入 分別認列為何？', '["應收帳款$18,000；銷貨收入$18,000", "應收帳款$18,000；銷貨收入$20,000", "應收帳款$20,000；銷貨收入$20,000", "應收帳款$20,000；銷貨收入$18,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00221', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司X7年度之部分財務資料如下：①利息支出$330,000；②稅前淨利$1,500,000；③所得', '["本期淨利$1,220,000；⑤資產總額$19,860,000；⑥負債總額$7,700,000； ⑦權益總額$12,160,000。試問：X7年度利息保障倍數為何？", "2.58", "3.70", "4.55"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
